import { Component, Event, EventEmitter, h, Host, Method, Prop, State, Watch } from '@stencil/core';
import { TreeMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item.interface';
import cloneDeep from 'lodash/cloneDeep';
import {
  findItemInArrayByUuid,
  findRootParent,
  setDisplayChildrenStatus,
  setParentStatus
} from '@src/mx-components/menu-item/mx-menu-item/menu-item-utils';
import { getNewUuid, removeUuidForItemWithChildren, setNewUuidsForNestedItems } from '@src/utils/mx-utils/item-uuids';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-pick-list-container',
  styleUrl: 'mx-pick-list-container.css',
  shadow: false
})
export class MxPickListContainer {
  /** Sets the items on the source list.
   * This prop can be used to setup tree like list in the pick list.
   * Look at the examples (JS) tab for more information. */
  @Prop() readonly items: TreeMenuItem[] = [];

  @Watch('items')
  handleItemsChange(_: TreeMenuItem[]) {
    setNewUuidsForNestedItems(this.items, 'children');
    if (this.items.length === 0) {
      this.filteredItems = [];
      this.displayNoResults = true;
    } else if (this.items.length > 0 && this.filteredItems.length === 0) {
      this.filteredItems = [...this.items];
      this.displayNoResults = false;
    } else {
      this.filteredItems = [...this.items];
    }
    this.updateSelectAllStatus(this.filteredItems);
    this.handleSearch(null);
  }

  /** Determines the width of the item lists. */
  @Prop() readonly width: number = 300;
  /** Sets the height of the list container. */
  @Prop() readonly height: number = 300;
  /** Sets compact checkboxes. */
  @Prop() readonly isCompact: boolean = false;
  /** Sets the label for the list container. */
  @Prop() readonly label: string;
  /** Sets the text to be displayed when no results are found. */
  @Prop() readonly emptyResultsLabel: string = 'No Results Found';
  /** Hides the list count if set to true. */
  @Prop() readonly hideCount: boolean = false;
  /** Shows/hides the child count in the menu-items. */
  @Prop() readonly showChildCount: boolean = false;
  /** Shows/hides carets in the menu-items. */
  @Prop() readonly hideCaret: boolean = false;

  /** Sets callback function to be called when an item is selected/deselected or if the selectAll is selected/deselected. */
  @Event() listContainerEvent: EventEmitter<TreeMenuItem[]>;
  /** Sets callback function to be called when an unexpanded item in the source list is opened. */
  @Event() listOpenEvent: EventEmitter<TreeMenuItem>;
  /** Sets callback function to be called when a expanded item in the source list is closed. */
  @Event() listCloseEvent: EventEmitter<TreeMenuItem>;

  /** Method to reset the Select All item status to an unselected state. */
  @Method()
  async unselectSelectAll() {
    this.selectAllItem.selected = false;
    this.selectAllItem.indeterminate = false;
  }

  /** Resets the Pick List Container to its original settings. Useful for user-cancelled interactions. */
  @Method()
  async resetPickListContainer() {
    this.selectableSearchText = '';
    this.searchInputRef.value = '';
  }

  @State() filteredItems: TreeMenuItem[] = this.items;
  @State() selectableSearchText = '';
  @State() displayNoResults: boolean = this.items.length === 0;
  @State() selectAllItem: TreeMenuItem = {
    label: 'Select All',
    value: 'all',
    selected: false,
    disabled: false,
    indeterminate: false,
    uuid: getNewUuid()
  };
  @State() listCount: number;

  private searchInputRef: HTMLMxSearchInputElement;

  constructor() {
    // In case this is being used independently(without pick-list)
    setNewUuidsForNestedItems(this.items, 'children');
  }

  componentWillLoad() {
    this.listCount = this.filteredItems.filter((it) => !it.disabled).length;
  }

  componentWillRender() {
    this.listCount = this.filteredItems.filter((it) => !it.disabled).length;
    this.updateSelectAllStatus(this.filteredItems);
  }

  private readonly handleSearch = (event: CustomEvent) => {
    if (!isNullOrUndefined(event)) {
      this.selectableSearchText = event.detail?.searchText;
    }
    const result = this.search(this.items, []);
    this.filteredItems = [...result];
    this.displayNoResults = this.filteredItems.length === 0;
  };

  private readonly handleMenuOpen = (event: CustomEvent<TreeMenuItem>) => {
    const item = event.detail;
    const updateItem = findItemInArrayByUuid(this.filteredItems, item.uuid);
    if (!isNullOrUndefined(updateItem)) {
      updateItem.displayChildren = item.displayChildren;
    }
    const itemWithoutUuid = removeUuidForItemWithChildren(cloneDeep(item), 'children');
    this.listOpenEvent.emit(itemWithoutUuid);
  };

  private readonly handleMenuClose = (event: CustomEvent<TreeMenuItem>) => {
    const item = event.detail;
    const updateItem = findItemInArrayByUuid(this.filteredItems, item.uuid);
    if (!isNullOrUndefined(updateItem)) {
      updateItem.displayChildren = item.displayChildren;
    }
    const itemWithoutUuid = removeUuidForItemWithChildren(cloneDeep(item), 'children');
    this.listCloseEvent.emit(itemWithoutUuid);
  };

  private updateSelectAllStatus(filteredItems: TreeMenuItem[]) {
    if (this.items.length === 0) {
      return;
    }
    const indeterminateCount = filteredItems.filter((it) => it.indeterminate && !it.selected).length;
    const selectedCount = filteredItems.filter((it) => it.selected).length;
    let selected = selectedCount > 0 && selectedCount === filteredItems.length;
    let indeterminate = false;
    if (!selected) {
      indeterminate = (selectedCount < filteredItems.length) || (indeterminateCount > 0);
    }
    if (selectedCount === 0) {
      selected = false;
      indeterminate = false;
    }
    if (indeterminateCount > 0) {
      indeterminate = true;
      selected = false;
    }
    this.selectAllItem = { ...this.selectAllItem, selected, indeterminate };
  }

  private copyItemSelectionStatus(oldItem: TreeMenuItem, newItem: TreeMenuItem) {
    newItem.selected = oldItem.selected;
    newItem.indeterminate = oldItem.indeterminate;
    if (!isNullOrUndefined(newItem.children)) {
      newItem.children.forEach((newChild) => {
        const oldChild = oldItem.children?.find((it) => it.uuid === newChild.uuid);
        if (!isNullOrUndefined(oldChild)) {
          this.copyItemSelectionStatus(oldChild, newChild);
        }
      });
    }
  }

  private updateItemSelectedStatus(item: TreeMenuItem, menuItemArray: TreeMenuItem[]) {
    const findItem = menuItemArray.find((it) => {
      const rootParent = findRootParent(it);
      if (rootParent.uuid === item.uuid) {
        return it;
      }
    });
    if (!isNullOrUndefined(findItem)) {
      this.copyItemSelectionStatus(item, findItem);
    }
  }

  private readonly setSelectAllState = (event: CustomEvent<TreeMenuItem>) => {
    const updatedItem: TreeMenuItem = event.detail;
    this.updateItemSelectedStatus(updatedItem, this.filteredItems);
    this.updateItemSelectedStatus(updatedItem, this.items);
    this.updateSelectAllStatus(this.filteredItems);
    this.listContainerEvent.emit(this.items);
  };

  private readonly toggleSelectAll = (event: CustomEvent<TreeMenuItem>) => {
    const selectAllItem = event.detail;
    let selected = selectAllItem.selected;
    const indeterminate = selectAllItem.indeterminate;
    if (indeterminate) {
      const totalCount = this.filteredItems.length;
      const selectedItemsCount = this.filteredItems.filter((it) => it.selected).length;
      const indeterminateItemsCount = this.filteredItems.filter((it) => it.indeterminate && !it.disabled).length;
      if (selectedItemsCount > 0 && (selectedItemsCount < totalCount)) {
        selected = true;
      } else {
        if (indeterminateItemsCount > 0) {
          selected = true;
        }
      }
    }
    if (selected) {
      this.filteredItems.forEach((item) => {
        setDisplayChildrenStatus(item, true);
      });
    }
    this.setFilteredItemsStatus(selected);
    this.updateSelectAllStatus(this.filteredItems);
    this.listContainerEvent.emit(this.items);
  };

  private setFilteredItemsStatus(selected: boolean) {
    this.filteredItems.forEach((item) => {
      if (!item.disabled) {
        item.selected = selected;
        if (item.selected) {
          item.indeterminate = false;
        }
        setParentStatus(item.parent);
        this.setChildrenStatus(item.children, selected);
        const rootItem = findRootParent(item);
        if (!isNullOrUndefined(rootItem)) {
          this.updateItemSelectedStatus(rootItem, this.items);
        }
      }
    });
    this.filteredItems = cloneDeep(this.filteredItems);
  }

  private search(items: TreeMenuItem[], result: any[]) {
    items.forEach((item) => {
      if (item.label.toLowerCase().includes(this.selectableSearchText.toLowerCase())) {
        result.push(item);
      } else if (item.children && item.children.length > 0) {
        this.search(item.children, result);
      }
    });
    return result;
  }

  private setChildrenStatus(children: TreeMenuItem[], status) {
    if (isNullOrUndefined(children)) {
      return;
    }
    children.filter((child) => {
      return isNullOrUndefined(child.disabled) || !child.disabled;
    }).forEach((child) => {
      child.selected = status;
      child.indeterminate = false;
      this.setChildrenStatus(child.children, status);
      setParentStatus(child.parent);
    });
  }

  private getViewPortHeight() {
    return this.height - 50;
  }

  render() {
    return (
      <Host>
        {!this.hideCount ? <h4 class='my-16 body-m'>{this.label}: {this.listCount}</h4> : ''}
        <div class='selectable-list border-neutral-less-prominent' style={{ width: this.width + 'px' }}>
          <div class='p-4'>
            <mx-search-input
              ref={(ref) => this.searchInputRef = ref}
              class='filter-search'
              onInputChanged={this.handleSearch}
              isCompact={this.isCompact}
              keyStrokes={1}>
            </mx-search-input>
          </div>
          <hr class='m-0 border' style={{ borderStyle: 'inset' }} />
          <ul class='my-0 p-0' style={{ height: this.height + 'px', minWidth: '150px' }}>
            {this.displayNoResults &&
              <mx-menu-item
                class='no-results-addable'
                label={this.emptyResultsLabel}
                showCheckbox={false}
                isDisabled={false}
                compactCheckbox={this.isCompact}
              ></mx-menu-item>
            }
            {this.filteredItems && this.filteredItems.length > 0 &&
              <mx-menu-item
                item={this.selectAllItem}
                key={this.selectAllItem.uuid}
                class={{
                  'select-all-addable': true
                }}
                showCheckbox={true}
                isDisabled={false}
                compactCheckbox={this.isCompact}
                onMenuItemSelected={this.toggleSelectAll}
              ></mx-menu-item>}
            <hr class='m-0 border' style={{ borderStyle: 'inset' }} />
            <div class='overflow-auto pt-16' style={{ height: this.getViewPortHeight() + 'px' }}>
              {this.filteredItems.map((item) =>
                <mx-menu-item
                  item={item}
                  key={item.uuid}
                  class='addable-menu-item'
                  isDisabled={item.disabled}
                  showTitle={true}
                  showCheckbox={!item.hideCheckbox}
                  displayChildren={item.displayChildren}
                  compactCheckbox={this.isCompact}
                  hideCaret={this.hideCaret}
                  emitTree={true}
                  showChildCount={this.showChildCount || item?.showChildCount}
                  onMenuItemOpened={this.handleMenuOpen}
                  onMenuItemClosed={this.handleMenuClose}
                  onMenuItemEvent={this.setSelectAllState}
                ></mx-menu-item>)}
            </div>
          </ul>
        </div>
      </Host>
    );
  }
}
